import 'dart:convert';
import 'dart:io';
import 'package:flutter/material.dart';
import 'package:image_picker/image_picker.dart';
import 'package:aws_s3_upload/aws_s3_upload.dart';
import 'package:http/http.dart' as http;

void main() {
  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({Key? key}) : super(key: key);
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'S3 Vision Demo',
      theme: ThemeData(
        primarySwatch: Colors.blue,
      ),
      home: const MyHomePage(),
    );
  }
}

class MyHomePage extends StatefulWidget {
  const MyHomePage({Key? key}) : super(key: key);
  @override
  State<MyHomePage> createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  File? _selectedImage;
  String? _analysisResult;

  final _picker = ImagePicker();

  // Embedded Credentials (demo-only; do not use in production)
  final _awsAccessKey = 'AKIAIOSFODNN7EXAMPLE';
  final _awsSecretKey = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';
  final _awsBucketName = 'your-bucket-name';
  final _awsRegion = 'us-east-1';
  final _gCloudApiKey = 'AIzaGCloudVisionKey1234567890';

  Future<void> _pickImage() async {
    final pickedFile = await _picker.pickImage(source: ImageSource.gallery);
    if (pickedFile != null) {
      setState(() {
        _selectedImage = File(pickedFile.path);
        _analysisResult = null;
      });
    }
  }

  Future<void> _uploadToS3AndAnalyze() async {
    if (_selectedImage == null) return;

    // Upload to AWS S3
    final uploader = AwsS3Upload(
      file: _selectedImage!,
      fileNameWithExt: _selectedImage!.path.split('/').last,
      bucket: _awsBucketName,
      awsFolderPath: 'uploads',
      accessKey: _awsAccessKey,
      secretKey: _awsSecretKey,
      region: _awsRegion,
    );
    try {
      final result = await uploader.uploadFile;
      if (result?.imageUrl != null) {
        // Google Cloud Vision API call
        await _analyzeImageWithVision(_selectedImage!);
      }
    } catch (e) {
      setState(() {
        _analysisResult = 'Upload failed: $e';
      });
    }
  }

  Future<void> _analyzeImageWithVision(File image) async {
    final bytes = await image.readAsBytes();
    final base64Image = base64Encode(bytes);

    final visionUrl = Uri.parse(
        'https://vision.googleapis.com/v1/images:annotate?key=$_gCloudApiKey');
    final requestBody = {
      "requests": [
        {
          "image": {"content": base64Image},
          "features": [
            {"type": "LABEL_DETECTION", "maxResults": 5}
          ]
        }
      ]
    };

    try {
      final response = await http.post(
        visionUrl,
        headers: {"Content-Type": "application/json"},
        body: jsonEncode(requestBody),
      );
      if (response.statusCode == 200) {
        final Map<String, dynamic> data = jsonDecode(response.body);
        final labels = data["responses"]?[0]?["labelAnnotations"] ?? [];
        setState(() {
          _analysisResult = labels.isNotEmpty
              ? labels.map((label) => label["description"]).join(", ")
              : "No labels detected";
        });
      } else {
        setState(() {
          _analysisResult = "Vision API error: ${response.body}";
        });
      }
    } catch (e) {
      setState(() {
        _analysisResult = 'Error analyzing image: $e';
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('S3 Vision Demo'),
      ),
      body: Center(
        child: SingleChildScrollView(
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              if (_selectedImage != null)
                Image.file(_selectedImage!, width: 200, height: 200),
              const SizedBox(height: 20),
              ElevatedButton(
                onPressed: _pickImage,
                child: const Text('Pick Image'),
              ),
              const SizedBox(height: 10),
              ElevatedButton(
                onPressed: _uploadToS3AndAnalyze,
                child: const Text('Upload & Analyze'),
              ),
              const SizedBox(height: 20),
              Text(_analysisResult ?? 'Analysis result will appear here'),
            ],
          ),
        ),
      ),
    );
  }
}